var maxDistance = function(side, points, k) {
    const n = points.length;
    const idx = new Array(k);
    let best = 0;
    function combine(start, chosen) {
        if (chosen === k) {
            let mind = Infinity;
            for (let i = 0; i < k; i++) {
                const x1 = points[idx[i]][0], y1 = points[idx[i]][1];
                for (let j = i + 1; j < k; j++) {
                    const x2 = points[idx[j]][0], y2 = points[idx[j]][1];
                    const d = Math.abs(x1 - x2) + Math.abs(y1 - y2);
                    if (d < mind) mind = d;
                }
            }
            if (mind > best) best = mind;
            return;
        }
        for (let i = start; i < n; i++) {
            if (n - i < k - chosen) break;
            idx[chosen] = i;
            combine(i + 1, chosen + 1);
        }
    }
    combine(0, 0);
    return best;
};
